// ⚠️ Discord Webhook URL — n8n Credentials 에서 복사해서 여기에 붙여넣기
const DISCORD_WEBHOOK_URL = 'https://discord.com/api/webhooks/YOUR_ID/YOUR_TOKEN';

const body = $input.first().json.body || {};
const { event, asset_type, new_state } = body;

let action = 'unknown';

if (event === 'all_approved' && asset_type === 'image') action = 'generate_tts';
else if (event === 'all_approved' && asset_type === 'tts') action = 'assemble';
else if (event === 'state_change' && new_state === 'approved') action = 'generate_images';
else if (event === 'state_change' && new_state) action = 'notify';
else if (event === 'job_complete') action = 'notify_complete';
else if (event === 'job_failed') action = 'notify_error';

return [{ json: { body, action, webhook_url: DISCORD_WEBHOOK_URL } }];

const body = $input.first().json.body;
const webhookUrl = $input.first().json.webhook_url;

const stateLabels = {
  'scenario_review': '시나리오 리뷰',
  'approved': '시나리오 승인',
  'image_review': '이미지 리뷰',
  'tts_review': 'TTS 리뷰',
  'assembling': '조립 중',
  'complete': '완료'
};

const stateColors = {
  'scenario_review': 16244463,
  'approved': 3066993,
  'image_review': 15105570,
  'tts_review': 3447003,
  'assembling': 10181046,
  'complete': 3066993
};

const stateEmojis = {
  'scenario_review': '📝',
  'approved': '✅',
  'image_review': '🖼️',
  'tts_review': '🔊',
  'assembling': '🎬',
  'complete': '🎉'
};

const stateDescs = {
  'scenario_review': '시나리오가 생성되었습니다. 리뷰해주세요.',
  'approved': '시나리오가 승인되었습니다.',
  'image_review': '이미지 생성이 완료되었습니다. 리뷰해주세요.',
  'tts_review': 'TTS 생성이 완료되었습니다. 리뷰해주세요.',
  'assembling': 'CapCut 프로젝트 조립이 시작되었습니다.',
  'complete': '모든 작업이 완료되었습니다!'
};

const stateAnchors = {
  'scenario_review': '#scenario',
  'image_review': '#images',
  'tts_review': '#tts'
};

const state = body.new_state || 'unknown';
const emoji = stateEmojis[state] || '📋';
const label = stateLabels[state] || state;
const color = stateColors[state] || 9807270;
const desc = stateDescs[state] || state + ' 단계로 전환되었습니다.';
const anchor = stateAnchors[state] || '';
const reviewURL = 'https://review.eli.kr' + body.review_url + anchor;

return [{
  json: {
    webhook_url: webhookUrl,
    embeds: [{
      title: emoji + ' ' + body.scp_id + ' — ' + label,
      url: reviewURL,
      description: desc,
      color: color,
      fields: [
        { name: '프로젝트', value: body.project_id, inline: true },
        { name: '상태 변경', value: (body.previous_state || '?') + ' → ' + state, inline: true }
      ],
      timestamp: new Date().toISOString()
    }]
  }
}];

const body = $input.first().json.body;
const webhookUrl = $input.first().json.webhook_url;

const jobLabels = {
  'image_generate': '이미지 생성',
  'tts_generate': 'TTS 생성',
  'assembly': 'CapCut 조립',
  'pipeline_run': '파이프라인'
};

const jobAnchors = {
  'image_generate': '#images',
  'tts_generate': '#tts',
  'assembly': ''
};

const jobType = body.job_type || 'unknown';
const label = jobLabels[jobType] || jobType;
const anchor = jobAnchors[jobType] || '';
const sceneAnchor = body.failed_scene > 0 ? '#scene-' + body.failed_scene : anchor;
const reviewURL = 'https://review.eli.kr' + body.review_url + sceneAnchor;

const fields = [
  { name: '작업', value: label, inline: true },
  { name: '프로젝트', value: body.project_id, inline: true }
];

if (body.failed_scene > 0) {
  fields.push({ name: '실패 씬', value: 'Scene ' + body.failed_scene, inline: true });
}

return [{
  json: {
    webhook_url: webhookUrl,
    embeds: [{
      title: '🚨 ' + body.scp_id + ' — ' + label + ' 실패',
      url: reviewURL,
      description: '```\n' + body.error + '\n```',
      color: 15158332,
      fields: fields,
      timestamp: new Date().toISOString()
    }]
  }
}];

const body = $input.first().json.body;
const webhookUrl = $input.first().json.webhook_url;

const jobLabels = {
  'image_generate': '이미지 생성',
  'tts_generate': 'TTS 생성',
  'assembly': 'CapCut 조립',
  'pipeline_run': '파이프라인',
  'dry_run': '드라이런'
};

const jobEmojis = {
  'image_generate': '🖼️',
  'tts_generate': '🔊',
  'assembly': '🎬',
  'pipeline_run': '🚀',
  'dry_run': '🧪'
};

const jobDescs = {
  'image_generate': '이미지가 모두 생성되었습니다. 리뷰해주세요.',
  'tts_generate': 'TTS 음성이 모두 생성되었습니다. 리뷰해주세요.',
  'assembly': 'CapCut 프로젝트 조립이 완료되었습니다!',
  'pipeline_run': '파이프라인 실행이 완료되었습니다.',
  'dry_run': '드라이런이 완료되었습니다.'
};

const jobAnchors = {
  'image_generate': '#images',
  'tts_generate': '#tts',
  'assembly': ''
};

const jobType = body.job_type || 'unknown';
const label = jobLabels[jobType] || jobType;
const emoji = jobEmojis[jobType] || '✅';
const desc = jobDescs[jobType] || label + ' 작업이 완료되었습니다.';
const anchor = jobAnchors[jobType] || '';
const reviewURL = 'https://review.eli.kr' + body.review_url + anchor;

const fields = [
  { name: '프로젝트', value: body.project_id, inline: true },
  { name: '작업', value: label, inline: true }
];

if (body.result) {
  const paths = body.result.split(',');
  fields.push({ name: '결과', value: paths.length + '개 파일', inline: true });
}

return [{
  json: {
    webhook_url: webhookUrl,
    embeds: [{
      title: emoji + ' ' + body.scp_id + ' — ' + label + ' 완료',
      url: reviewURL,
      description: desc,
      color: 3066993,
      fields: fields,
      timestamp: new Date().toISOString()
    }]
  }
}];
